updateUser: (_, { id, input }, ctx) => {
  if (ctx.user?.id !== id && !ctx.user?.isAdmin)
    throw new GraphQLError('Forbidden', { extensions: { code: 'FORBIDDEN' } });
  return ctx.db.users.update(id, input);
}

